function FloatingPetals() {
  const petals = Array.from({ length: 16 }, (_, i) => ({
    id: i,
    left: `${Math.random() * 100}%`,
    delay: `${Math.random() * 8}s`,
    duration: `${6 + Math.random() * 6}s`,
    size: `${13 + Math.random() * 12}px`,
    emoji: ["🌸", "🌺", "✨", "🌼", "💮"][i % 5],
  }));
  return (
    <div style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 0, overflow: "hidden" }}>
      {petals.map((p) => (
        <div key={p.id} style={{ position: "absolute", left: p.left, top: "-30px", fontSize: p.size, animation: `petalFall ${p.duration} ${p.delay} infinite linear`, opacity: 0.65 }}>{p.emoji}</div>
      ))}
    </div>
  );
}

function GlowCircles() {
  return (
    <div style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 0, overflow: "hidden" }}>
      {[{ top: "5%", left: "-12%", size: 320 }, { top: "55%", right: "-12%", size: 260 }, { bottom: "8%", left: "28%", size: 200 }].map((c, i) => (
        <div key={i} style={{ position: "absolute", top: c.top, left: c.left, right: c.right, bottom: c.bottom, width: c.size, height: c.size, borderRadius: "50%", background: "radial-gradient(circle, rgba(236,72,153,0.13) 0%, transparent 70%)", animation: `pulseGlow ${3 + i}s ease-in-out infinite alternate` }} />
      ))}
    </div>
  );
}

function Balloon({ color, index, message, photo }) {
  // States: "floating" | "popping" | "popped" | "blowing"
  const [state, setState] = useState("floating");
  const [confetti, setConfetti] = useState([]);
  const timerRef = useRef(null);

  const handleClick = () => {
    if (state !== "floating") return;
    // pop
    setState("popping");
    const pieces = Array.from({ length: 22 }, (_, i) => ({
      id: i,
      x: (Math.random() - 0.5) * 180,
      y: (Math.random() - 0.5) * 180,
      color: ["#FFD700","#FF69B4","#FF6B6B","#A78BFA","#34D399","#F97316"][i % 6],
      size: 7 + Math.random() * 7,
      rotate: Math.random() * 360,
    }));
    setConfetti(pieces);
    setTimeout(() => { setState("popped"); setConfetti([]); }, 400);
    // auto blow back after 4 seconds
    timerRef.current = setTimeout(() => {
      setState("blowing");
      setTimeout(() => setState("floating"), 700);
    }, 4200);
  };

  useEffect(() => () => clearTimeout(timerRef.current), []);

  const isRow2 = index >= 3;

  return (
    <div style={{
      position: "absolute",
      left: BALLOON_POSITIONS[index].left,
      top: isRow2 ? "220px" : "10px",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      cursor: state === "floating" ? "pointer" : "default",
      zIndex: 10,
    }} onClick={handleClick}>

      {/* Confetti burst */}
      {confetti.map((c) => (
        <div key={c.id} style={{
          position: "absolute", top: "40%", left: "50%",
          width: c.size, height: c.size, borderRadius: 2,
          background: c.color,
          transform: `translate(${c.x}px, ${c.y}px) rotate(${c.rotate}deg)`,
          animation: "confettiBurst 0.8s ease-out forwards",
          pointerEvents: "none", zIndex: 50,
        }} />
      ))}

      {/* BALLOON BODY */}
      {(state === "floating" || state === "popping" || state === "blowing") && (
        <div style={{
          animation: state === "floating"
            ? `balloonFloat ${2.5 + index * 0.4}s ease-in-out infinite alternate`
            : state === "popping"
            ? "balloonPop 0.3s ease-out forwards"
            : "balloonBlow 0.7s ease-out forwards",
          transformOrigin: "bottom center",
        }}>
          <div style={{ position: "relative", width: 82, height: 100 }}>
            <div style={{
              width: 82, height: 100,
              borderRadius: "50% 50% 50% 50% / 55% 55% 45% 45%",
              background: `radial-gradient(circle at 35% 30%, ${color.shine}, ${color.bg} 58%, ${color.shadow})`,
              boxShadow: `0 10px 28px ${color.bg}66, inset -8px -12px 20px ${color.shadow}44`,
              position: "relative",
            }}>
              <div style={{ position: "absolute", top: "18%", left: "22%", width: "28%", height: "20%", borderRadius: "50%", background: "rgba(255,255,255,0.55)", transform: "rotate(-30deg)" }} />
            </div>
            <div style={{ position: "absolute", bottom: -6, left: "50%", transform: "translateX(-50%)", width: 8, height: 10, background: color.shadow, borderRadius: "0 0 50% 50%" }} />
          </div>
          <svg width="4" height="65" viewBox="0 0 4 65" style={{ display: "block" }}>
            <path d="M2,0 Q4,16 2,32 Q0,48 2,65" stroke="#aaa" strokeWidth="1.2" fill="none" />
          </svg>
        </div>
      )}

      {state === "popping" && (
        <div style={{ fontSize: 32, position: "absolute", top: "20px" }}>💥</div>
      )}

      {/* POPPED: show photo card */}
      {state === "popped" && (
        <div style={{
          animation: "cardReveal 0.5s cubic-bezier(0.34,1.56,0.64,1) forwards",
          transformOrigin: "top center",
        }}>
          <div style={{
            background: "rgba(255,255,255,0.95)",
            backdropFilter: "blur(16px)",
            borderRadius: 20,
            padding: "12px",
            boxShadow: "0 8px 40px rgba(236,72,153,0.25)",
            border: "2px solid rgba(236,72,153,0.25)",
            width: 150,
            textAlign: "center",
          }}>
            {/* Photo */}
            <div style={{ width: 126, height: 110, borderRadius: 12, overflow: "hidden", marginBottom: 8, border: "2px solid rgba(232,51,109,0.3)" }}>
              <img src={photo} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
            </div>
            <p style={{ fontFamily: "'Cormorant Garamond', serif", fontStyle: "italic", fontSize: 12, color: "#8B1A3A", lineHeight: 1.5 }}>
              {message}
            </p>
            <div style={{ fontSize: 10, color: "#C2185B", marginTop: 6, fontFamily: "'Poppins', sans-serif", opacity: 0.6 }}>tap balloon again ↑</div>
          </div>
        </div>
      )}
    </div>
  );
}

function MusicPlayer({ playing, onToggle }) {
  return (
    <div onClick={onToggle} style={{ position: "fixed", bottom: 24, right: 16, background: "rgba(255,255,255,0.92)", backdropFilter: "blur(12px)", borderRadius: 50, padding: "10px 16px", display: "flex", alignItems: "center", gap: 10, boxShadow: "0 4px 20px rgba(236,72,153,0.2)", border: "1px solid rgba(236,72,153,0.2)", zIndex: 100, cursor: "pointer", userSelect: "none" }}>
      <div style={{ display: "flex", alignItems: "flex-end", gap: 2, height: 18 }}>
        {[1, 2, 3, 4].map((b) => (
          <div key={b} style={{ width: 3, borderRadius: 2, background: "#E8336D", height: playing ? undefined : 4, animation: playing ? `eq${b} ${0.5 + b * 0.15}s ease-in-out infinite alternate` : "none" }} />
        ))}
      </div>
      <span style={{ fontSize: 12, fontFamily: "'Poppins', sans-serif", color: "#9B2B5A", fontWeight: 600 }}>♪ {playing ? "Playing" : "Paused"}</span>
      <div style={{ width: 28, height: 28, borderRadius: "50%", background: "#E8336D", display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontSize: 11 }}>{playing ? "⏸" : "▶"}</div>
    </div>
  );
}

